#include <bits/stdc++.h>
using namespace std;
const int maxn=1e5+5;
int n,m,q,a[maxn];
inline bool cmp(int a,int b){
	return a>b;
}
int main() {
    ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>m;
	for(int i=1; i<=n; i++) {
		cin>>a[i];
	}
	while(m--) {
		int op,l,r;
		cin>>op>>l>>r;
		if(op==0) {
			sort(a+l,a+r+1);
		} else {
			sort(a+l,a+r+1,cmp);
		}
	}
	cin>>q;
	cout<<a[q];
	return 0;
}
